import{_ as o,o as t,c as a,ae as n}from"./chunks/framework.B6gjLfeO.js";const p=JSON.parse('{"title":"Advanced Settings & Change Your Link Domain","description":"","frontmatter":{"title":"Advanced Settings & Change Your Link Domain","slug":"advanced-settings-configuration-deprecated"},"headers":[],"relativePath":"marketer-hub/advanced-settings-configuration-deprecated.md","filePath":"marketer-hub/advanced-settings-configuration-deprecated.md"}'),i={name:"marketer-hub/advanced-settings-configuration-deprecated.md"};function r(s,e,d,c,l,h){return t(),a("div",null,[...e[0]||(e[0]=[n('<h2 id="link-domain" tabindex="-1">Link domain <a class="header-anchor" href="#link-domain" aria-label="Permalink to &quot;Link domain&quot;">​</a></h2><p>To see your app’s default link domain and alternate link domain, navigate to the <a href="https://dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">General tab</a> of the App Settingspage of the Branch Dashboard.</p><p>When you first create your account, you will be assigned a unique domain for all of your Branch Links.</p><h3 id="change-link-domain" tabindex="-1">Change link domain <a class="header-anchor" href="#change-link-domain" aria-label="Permalink to &quot;Change link domain&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Before changing your Branch link domain, it is important to understand all behavior changes that occur when you do so. This will help ensure you do not run into any unwanted experiences for your users clicking your Branch Links.</p></div><table tabindex="0"><thead><tr><th>Change</th><th>Example</th><th>Behavior</th></tr></thead><tbody><tr><td><code>app.link</code> to <code>app.link</code></td><td><code>abcdef.app.link</code> → <code>mycompany.app.link</code></td><td>- Your old <code>app.link</code> URLs will redirect to the <strong>LINK NOT FOUND</strong> page. - Your old <code>app.link</code> URLs will fail to open your mobile app. - Your new <code>app.link</code> URLs will not open your app until you update your code to utilize the new link domain (<a href="./ios-basic-integration.html">iOS</a> / <a href="./android-basic-integration.html">Android</a>). - If you are already using your original/old <code>app.link</code> URLs in the wild and need them to keep working, it is recommended to explore <a href="./advanced-settings-configuration.html#using-your-own-domain">Using Your Own Domain</a> instead.</td></tr><tr><td><code>app.link</code> to Custom Domain</td><td><code>mycompany.app.link</code> → <code>app.mycompany.com</code></td><td>- Your old <code>app.link</code> URLs will still work. - Your new Custom Domain URLs will not open your app until you update your code to utilize the new link domain (<a href="./ios-basic-integration.html">iOS</a> / <a href="./android-basic-integration.html">Android</a>). - <a href="./creating-a-deep-link.html">Creating Long Links Details</a></td></tr><tr><td>Custom Domain to Custom Domain</td><td><code>app.mycompany.com</code> → <code>mycompany.app</code></td><td>- Your old Custom Domain URLs will fail to deep link. - Your new Custom Domain URLs will not open your app until you update your code to utilize the new link domain (<a href="./ios-basic-integration.html">iOS</a> / <a href="./android-basic-integration.html">Android</a>).</td></tr><tr><td>Legacy <code>bnc.lt</code> to <code>app.link</code> or Custom Domain</td><td><code>bnc.lt</code> → <code>mycompany.app.link</code> <code>bnc.lt/branch</code> → <code>app.mycompany.com</code></td><td>- Both your <code>bnc.lt</code> and <code>app.link</code>/Custom Domain deep links will work. - Your new <code>app.link</code>/Custom Domain URLs will not open your app until you update your code to utilize the new link domain (<a href="./ios-basic-integration.html">iOS</a> / <a href="./android-basic-integration.html">Android</a>).</td></tr></tbody></table><h3 id="change-app-link-subdomain" tabindex="-1">Change app.link subdomain <a class="header-anchor" href="#change-app-link-subdomain" aria-label="Permalink to &quot;Change app.link subdomain&quot;">​</a></h3><div class="warning custom-block"><p class="custom-block-title">Caution</p><p>Changing your <code>app.link</code> subdomain can only be performed <strong>once</strong> for your Branch app.</p></div><p>You have the ability to change your <code>app.link</code> subdomain for your Branch Links to better match your brand. It is recommended to set your <code>app.link</code> subdomain to be the name of your app, in case you have multiple mobile apps under your brand.</p><p>To customize your <code>app.link</code> subdomain:</p><ol><li>Review and understand <a href="./advanced-settings-configuration.html#change-link-domain">what it means to change your domain</a>.</li><li>Click the <strong>Change My</strong> <code>app.link</code> <strong>Subdomain</strong> button.</li><li>Input your new preferred <code>app.link</code> subdomain. You can only set it to a subdomain that is not already taken by another Branch app.</li><li>Update your mobile app to use the new <code>app.link</code> subdomain.</li></ol><h3 id="use-your-own-domain" tabindex="-1">Use your own domain <a class="header-anchor" href="#use-your-own-domain" aria-label="Permalink to &quot;Use your own domain&quot;">​</a></h3><p>You have the ability to use your own custom domain to be used for your Branch Links. Branch supports the use of a custom subdomain or a custom root domain for you to be able to set your Branch Links closer to your branding preferences.</p><div class="danger custom-block"><p class="custom-block-title">Warning</p><p>Do not use your main website domain for your Branch Links.</p></div><div class="warning custom-block"><p class="custom-block-title">Caution</p><ul><li>Whenever you change the NS or CNAME records of your domain, you are making Branch the authoritative registrar of your domain. This will grant Branch control of your domain and you will lose access to that custom subdomain or custom root domain. The web page will become blank, and the control of the domain will change to Branch</li><li>Branch will use the domain to route all deep linked traffic.</li><li>Branch will host your AASA file and SSL certifications.</li><li>If you have content on your custom root domain, Branch recommends using an unused custom subdomain.</li></ul></div><table tabindex="0"><thead><tr><th>Limitation</th><th>Details</th></tr></thead><tbody><tr><td>Android App Links &amp; Web Limitations</td><td>Android App Links together on custom subdomains and custom root domains currently do not support Branch&#39;s web-only link functionality. Using the <code>$web_only</code> parameter on Branch Links that only open the web even if the app is installed. Because of this limitation, <strong>Android App Links will force the app to open even when using the</strong> <code>$web_only</code> <strong>parameter</strong>.</td></tr><tr><td>Web</td><td>If you have Activation, you can use a custom domain for Web Short Links. For other packages, <strong>you must use the assigned default link alias</strong>.</td></tr></tbody></table><h4 id="use-a-custom-subdomain" tabindex="-1">Use a custom subdomain <a class="header-anchor" href="#use-a-custom-subdomain" aria-label="Permalink to &quot;Use a custom subdomain&quot;">​</a></h4><p>If your enterprise is highly restrictive of the domains that you utilize and wants to ensure that your Branch domain matches the rest of your relevant subdomains, you can utilize a custom subdomain, for example <code>link.yourbrand.com</code> .</p><p>To set a custom subdomain:</p><ol><li>Review and understand <a href="./advanced-settings-configuration.html#change-link-domain">what it means to change your link domain</a>.</li><li>Update the DNS CNAME of your custom subdomain to point to <code>custom.bnc.lt</code> . If using AWS Route 53, do this in the Registered Domain tab, not in Hosted Zones.</li><li>Use the <a href="https://www.entrust.com/resources/certificate-solutions/tools/caa-lookup" target="_blank" rel="noreferrer">CAA Lookup Tool</a> to see if you need to update your <code>CAA</code> records of your custom subdomain to include <code>letsencrypt.org</code>.</li><li>Click the <strong>Use My Own Domain</strong> button.</li><li>Input your custom subdomain (without the <code>www</code> ) and click <strong>Confirm</strong>.</li><li>Update your mobile app to use the new custom subdomain.</li></ol><h4 id="use-a-custom-root-domain" tabindex="-1">Use a custom root domain <a class="header-anchor" href="#use-a-custom-root-domain" aria-label="Permalink to &quot;Use a custom root domain&quot;">​</a></h4><p>If your enterprise requires you to establish an entirely separate domain for your Branch domain, you can use a custom root domain, for example <code>yourbrand-link.com</code>. This is only recommended if your company is not open to <code>app.link</code> or a custom subdomain option.</p><p>To set a custom root domain:</p><ol><li><p>Review and understand <a href="./advanced-settings-configuration.html#change-link-domain">what it means to change your link domain</a>.</p></li><li><p>Update the <code>NS</code> records of your custom root domain using the following nameservers:</p><ul><li><code>ns-1581.awsdns-05.co.uk</code></li><li><code>ns-234.awsdns-29.com</code></li><li><code>ns-1059.awsdns-04.org</code></li><li><code>ns-843.awsdns-41.net</code></li></ul></li><li><p>Use the <a href="https://www.entrust.com/resources/certificate-solutions/tools/caa-lookup" target="_blank" rel="noreferrer">CAA Lookup Tool</a> to see if you need to update your <code>CAA</code> records of your custom subdomain to include <code>letsencrypt.org</code>.</p></li><li><p>Click the <strong>Use My Own Domain</strong> button.</p></li><li><p>Input your custom root domain (without the <code>www</code>) and click <strong>Confirm</strong>.</p></li><li><p>Update your mobile app to use the new custom subdomain.</p></li></ol><h2 id="advanced-settings" tabindex="-1">Advanced settings <a class="header-anchor" href="#advanced-settings" aria-label="Permalink to &quot;Advanced settings&quot;">​</a></h2><p>On the <a href="https://branch.dashboard.branch.io/configuration/general" target="_blank" rel="noreferrer">Configuration Screen</a> of the Branch Dashboard, you can change your advanced link settings</p><h3 id="uri-scheme-deep-link" tabindex="-1">URI Scheme Deep Link <a class="header-anchor" href="#uri-scheme-deep-link" aria-label="Permalink to &quot;URI Scheme Deep Link&quot;">​</a></h3><p>This selector allows you to control how and when Branch uses URI schemes to open your app when Universal Links and Android App Links fail. See browser specifics in the docs <a href="./creating-a-deep-link.html#expected-link-behavior">here</a>.</p><table tabindex="0"><thead><tr><th>Deep Link Mode</th><th>Description</th></tr></thead><tbody><tr><td>Conservative</td><td>Conservative mode will never use URI schemes if there is a risk of error messages.</td></tr><tr><td>Intelligent</td><td>Intelligent mode is <strong>recommended</strong> and uses Branch data to safely use URI schemes everywhere, with the slight risk of error messages in certain browsers if the app is uninstalled.</td></tr><tr><td>Aggressive</td><td>Aggressive will force URI schemes everywhere, causing users without the app to see error messages in some browsers.</td></tr></tbody></table><h3 id="redirect-allowlist" tabindex="-1">Redirect Allowlist <a class="header-anchor" href="#redirect-allowlist" aria-label="Permalink to &quot;Redirect Allowlist&quot;">​</a></h3><p>With Branch, you have the ability to set a specific allowlist of domains that you can allow your Branch Links to redirect to (set to disabled by default). With the Redirect Allowlist, you can limit Branch Link redirection to specific web domains or URI schemes across your Branch platform. List each of the domains you want to limit redirection to. We also support a “*” for wildcard subdomains.</p><p>For example, if your allowlist includes “branch.io”, “*.branch.io”, and “myapp://”, your deep links can only redirect to domains like branch.io, dashboard.branch.io, or myapp://.</p><p>It is recommended that you include the app store domains that are relevant to the way users download your app. For example: “play.google.com” and “apps.apple.com”</p><h3 id="match-type" tabindex="-1">Match Type <a class="header-anchor" href="#match-type" aria-label="Permalink to &quot;Match Type&quot;">​</a></h3><p>Setting Match Type determines the matching methodology Branch uses for your Links and App. Selecting <strong>Unique</strong> means that Branch will only make a deep link through install match if there is a single, unique outstanding footprint. For example, if you and your twin both have iPhone 5s with the same OS/version, etc, and click different links for the same app, then open the app up at the same time, we won’t deep link when Unique is selected. You probably don’t want this as it’s mostly for very special circumstances.</p><h3 id="local-currency" tabindex="-1">Local Currency <a class="header-anchor" href="#local-currency" aria-label="Permalink to &quot;Local Currency&quot;">​</a></h3><p>Set the local currency of your Branch Dashboard if it is not USD. By setting your local currency, you can analyze marketing spend (cost) and revenue in your local currency. This also allows direct cost data comparison with ad partners who report their spending in a currency other than USD.</p><p>A field called <strong>Local Currency</strong> will be available on the Dashboard showing the currency configured in your <a href="./paid-ads-analytics.html">Ads Analytics</a> and <a href="./unified-analytics.html">Unified Analytics</a>.</p><p>Note: The currency can only be set once through the Branch Dashboard to avoid some potential issues:<br> Historical data does not switch to the new local currency but would be labeled as such. As a result, the data prior to the currency change may show as inaccurate.<br> When changing the currency type, your cost data for the previous 7 days will be updated and may cause inaccuracies.</p><h3 id="other-settings" tabindex="-1">Other Settings <a class="header-anchor" href="#other-settings" aria-label="Permalink to &quot;Other Settings&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Setting</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td>Use UTM tags for analytics (for <a href="./creating-a-deep-link.html#long-links">Long Links</a>)</td><td>Disabled</td><td>If you enable this, Branch will automatically set channel, feature, campaign, tags, and keywords based on UTM parameters. This only applies to Long Links, not links generated through the Dashboard, API, or SDKs.</td></tr><tr><td>Analytics mapping with UTM</td><td>Enabled</td><td>When redirecting to a web URL, Branch automatically passes through any values from the following Branch link analytics tags as UTM parameters [~campaign -&gt; utm_campaign, ~channel -&gt; utm_source, ~feature -&gt; utm_medium]. If these UTM parameters are already detected on the URLs being redirected to, Branch will not overwrite them.</td></tr><tr><td>Enable Link Scraping</td><td>Disabled</td><td>Please note that this setting does <strong>not</strong> apply to Branch Links made using the Dashboard <strong>or</strong> API-generated links. By default, Branch Links will scrape the original web URL for meta tags, and Branch Links made via API will scrape <code>$original_url</code>, <code>$fallback_url</code>, and <code>$desktop_url</code> for meta tags, in that order.</td></tr><tr><td>Enable retrieving Last Attributed Touch Data via SDKs</td><td>Disabled</td><td>Allow retrieving last attributed touch data from the client.</td></tr><tr><td>Enable China Features</td><td>Disabled</td><td>China Features include the ability to collect IMEI on non-Google Android devices.</td></tr></tbody></table><h3 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h3><p>For changing the Link Domain for both of your LIVE and TEST Branch apps, the best practice is to change your LIVE app first and then add <em>test</em> somewhere in the new domain name for the TEST app.</p><p>Notice, the LIVE and TEST apps cannot use the same customized Link Domain. For example, the LIVE app of <em>Branch Monster Factory</em> uses <code>branchster.app.link</code> for its LIVE app and <code>branchster.test-app.link</code> for its TEST app.</p>',44)])])}const m=o(i,[["render",r]]);export{p as __pageData,m as default};
